};

class PostgreSQL : public Database {
public:
    void connect() override { cout << "PostgreSQL connected" << endl; }
    string query(const string& sql) override {
        cout << "PostgreSQL: Executing '" << sql << "'" << endl;
        return "pg result";
    }
